module johnson_counter(rst, reset, q);

    input rst;
    input reset;
    output [2:0] q;
    reg [2:0] q;
    initial q = 3'b000;

    always @(posedge rst)
        begin
            if (reset)
                q <= 3'b000;
            else
                q <= {q[1:0], ~q[2]};
        end

endmodule
